def cache_result(ttl=3600):
    def decorator(func):
        def wrapper(*args, **kwargs):
            key = f'{func.__name__}{args}{kwargs}'
            result = memcached_client.get(key)
            if result is None:
                result = func(*args, **kwargs)
                memcached_client.set(key, result, expire=ttl)
                return result
            else:
                return result
        return wrapper
    return decorator

